opencat.script:
// ── sequential corner entrance ────────────────────────────
ctx.fromTo('video-tl', {opacity:0, x:-80, y:-80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:0.933333, ease:'spring.gentle'});
ctx.fromTo('video-tr', {opacity:0, x:80, y:-80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:0.933333, delay:0.6, ease:'spring.gentle'});
ctx.fromTo('video-bl', {opacity:0, x:-80, y:80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:0.933333, delay:1.2, ease:'spring.gentle'});
ctx.fromTo('video-br', {opacity:0, x:80, y:80, scale:0.85}, {opacity:1, x:0, y:0, scale:1, duration:0.933333, delay:1.8, ease:'spring.gentle'});
